// src/pages/ManageCourse.js
import React, { useState, useEffect } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import api from '../services/api';
import axios from 'axios';

// ─── helpers ──────────────────────────────────────────────────────────────────
const newLecture = () => ({
  localId: Date.now() + Math.random(),
  title: '',
  description: '',
  video_type: 'upload',
  video_url: '',
  file: null,
  s3_key: '',
  duration_minutes: 0,
  is_free_preview: false,
  uploadStatus: '',   // '' | 'uploading' | 'done' | 'error'
  uploadProgress: 0,
});

// ─── Sub-components ───────────────────────────────────────────────────────────

/** Single lecture row inside a section */
const LectureRow = ({ lec, sId, onUpdate, onRemove, onUpload }) => (
  <div style={s.lectureBox}>
    <div style={s.rowBetween}>
      <strong style={{ fontSize: 13, color: '#444' }}>🎬 ليكتشر</strong>
      <button style={s.btnDanger} onClick={() => onRemove(sId, lec.localId)}>حذف</button>
    </div>

    <label style={s.label}>عنوان الليكتشر *</label>
    <input style={s.input} value={lec.title}
      placeholder="مثال: مقدمة عن الكورس"
      onChange={(e) => onUpdate(sId, lec.localId, 'title', e.target.value)} />

    <label style={s.label}>وصف (اختياري)</label>
    <input style={s.input} value={lec.description}
      onChange={(e) => onUpdate(sId, lec.localId, 'description', e.target.value)} />

    <label style={s.label}>نوع المحتوى</label>
    <select style={s.input} value={lec.video_type}
      onChange={(e) => onUpdate(sId, lec.localId, 'video_type', e.target.value)}>
      <option value="upload">🎬 رفع فيديو على S3</option>
      <option value="youtube">▶ رابط YouTube</option>
      <option value="vimeo">▶ رابط Vimeo</option>
    </select>

    {/* ── Upload to S3 ── */}
    {lec.video_type === 'upload' && (
      <div style={s.uploadBox}>
        {lec.uploadStatus !== 'done' && (
          <>
            <label style={s.label}>📁 اختر ملف الفيديو</label>
            <input type="file" accept="video/mp4,video/webm,video/quicktime"
              style={{ marginBottom: 8 }}
              onChange={(e) => {
                const file = e.target.files[0];
                if (file) onUpdate(sId, lec.localId, 'file', file);
              }} />
            {lec.file && (
              <div style={s.fileInfo}>
                <span>📹 {lec.file.name}</span>
                <span style={{ color: '#666', fontSize: 12 }}>
                  {(lec.file.size / 1024 / 1024).toFixed(1)} MB
                </span>
              </div>
            )}
          </>
        )}

        {lec.file && lec.uploadStatus === '' && (
          <button type="button" style={s.btnUpload}
            onClick={() => onUpload(sId, lec.localId, lec.file)}>
            ⬆ ارفع الفيديو على S3
          </button>
        )}

        {lec.uploadStatus === 'uploading' && (
          <div style={{ marginTop: 8 }}>
            <div style={{ display: 'flex', justifyContent: 'space-between', fontSize: 13, marginBottom: 4 }}>
              <span>⏳ جاري الرفع...</span><span>{lec.uploadProgress}%</span>
            </div>
            <div style={s.progressWrap}>
              <div style={{ ...s.progressBar, width: `${lec.uploadProgress}%` }} />
            </div>
          </div>
        )}

        {lec.uploadStatus === 'done' && (
          <div style={s.uploadDone}>
            <span>✅ تم الرفع – في انتظار موافقة الأدمن</span>
            <button style={s.btnSmGray} onClick={() => {
              onUpdate(sId, lec.localId, 'file', null);
              onUpdate(sId, lec.localId, 's3_key', '');
              onUpdate(sId, lec.localId, 'uploadStatus', '');
              onUpdate(sId, lec.localId, 'uploadProgress', 0);
            }}>🔄 تغيير</button>
          </div>
        )}

        {lec.uploadStatus === 'error' && (
          <>
            <p style={{ color: '#dc3545', fontSize: 13, margin: '6px 0' }}>❌ فشل الرفع</p>
            <button style={s.btnUpload}
              onClick={() => onUpload(sId, lec.localId, lec.file)}>🔄 إعادة المحاولة</button>
          </>
        )}
      </div>
    )}

    {/* ── YouTube / Vimeo ── */}
    {lec.video_type !== 'upload' && (
      <div>
        <label style={s.label}>
          {lec.video_type === 'youtube' ? '▶ رابط YouTube' : '▶ رابط Vimeo'}
        </label>
        <input style={s.input} type="url"
          placeholder={lec.video_type === 'youtube'
            ? 'https://www.youtube.com/watch?v=...'
            : 'https://vimeo.com/...'}
          value={lec.video_url}
          onChange={(e) => onUpdate(sId, lec.localId, 'video_url', e.target.value)} />
        {lec.video_url && <p style={s.successTxt}>✅ الرابط جاهز</p>}
      </div>
    )}

    {/* ── Duration & free preview ── */}
    <div style={{ display: 'flex', gap: 16, marginTop: 8, alignItems: 'flex-end' }}>
      <div>
        <label style={s.label}>المدة (دقيقة)</label>
        <input style={{ ...s.input, width: 90 }} type="number" min="0"
          value={lec.duration_minutes}
          onChange={(e) => onUpdate(sId, lec.localId, 'duration_minutes', +e.target.value)} />
      </div>
      <label style={{ cursor: 'pointer', fontSize: 14, paddingBottom: 8 }}>
        <input type="checkbox" checked={lec.is_free_preview}
          onChange={(e) => onUpdate(sId, lec.localId, 'is_free_preview', e.target.checked)} />
        {' '}معاينة مجانية
      </label>
    </div>
  </div>
);

/** Single section card */
const SectionCard = ({ sec, idx, onUpdateSec, onRemoveSec,
                        onAddLec, onUpdateLec, onRemoveLec, onUpload }) => (
  <div style={s.sectionCard}>
    <div style={s.rowBetween}>
      <h3 style={{ margin: 0, fontSize: 16 }}>📂 القسم {idx + 1}</h3>
      <button style={s.btnDanger} onClick={() => onRemoveSec(sec.localId)}>حذف القسم</button>
    </div>

    <label style={s.label}>عنوان القسم *</label>
    <input style={s.input} value={sec.title}
      placeholder="مثال: الوحدة الأولى – المقدمة"
      onChange={(e) => onUpdateSec(sec.localId, 'title', e.target.value)} />

    <label style={s.label}>وصف القسم (اختياري)</label>
    <input style={s.input} value={sec.description}
      onChange={(e) => onUpdateSec(sec.localId, 'description', e.target.value)} />

    {/* Lectures */}
    <div style={{ marginTop: 12 }}>
      {sec.lectures.map((lec) => (
        <LectureRow key={lec.localId} lec={lec} sId={sec.localId}
          onUpdate={onUpdateLec} onRemove={onRemoveLec} onUpload={onUpload} />
      ))}
    </div>

    <button style={s.btnAddLec} onClick={() => onAddLec(sec.localId)}>
      + إضافة ليكتشر
    </button>
  </div>
);

// ─── Main Page ────────────────────────────────────────────────────────────────
const ManageCourse = () => {
  const { id: courseId } = useParams();
  const navigate = useNavigate();

  const [course, setCourse]       = useState(null);
  const [loading, setLoading]     = useState(true);
  const [saving, setSaving]       = useState(false);
  const [savedMsg, setSavedMsg]   = useState('');
  const [errorMsg, setErrorMsg]   = useState('');
  const [sections, setSections]   = useState([]);   // local draft sections

  // Load existing course info
  useEffect(() => {
    api.get(`/courses/${courseId}/`)
      .then((res) => setCourse(res.data))
      .catch(() => setErrorMsg('تعذّر تحميل الكورس'))
      .finally(() => setLoading(false));
  }, [courseId]);

  // ── Section CRUD ──────────────────────────────────────────────────────────
  const addSection = () =>
    setSections((prev) => [
      ...prev,
      { localId: Date.now(), title: '', description: '', order: prev.length, lectures: [] },
    ]);

  const removeSection = (sLocalId) =>
    setSections((prev) => prev.filter((s) => s.localId !== sLocalId));

  const updateSection = (sLocalId, field, value) =>
    setSections((prev) =>
      prev.map((s) => s.localId === sLocalId ? { ...s, [field]: value } : s)
    );

  // ── Lecture CRUD ──────────────────────────────────────────────────────────
  const addLecture = (sLocalId) =>
    setSections((prev) =>
      prev.map((s) =>
        s.localId === sLocalId
          ? { ...s, lectures: [...s.lectures, newLecture()] }
          : s
      )
    );

  const removeLecture = (sLocalId, lLocalId) =>
    setSections((prev) =>
      prev.map((s) =>
        s.localId === sLocalId
          ? { ...s, lectures: s.lectures.filter((l) => l.localId !== lLocalId) }
          : s
      )
    );

  const updateLecture = (sLocalId, lLocalId, field, value) =>
    setSections((prev) =>
      prev.map((s) =>
        s.localId === sLocalId
          ? { ...s, lectures: s.lectures.map((l) =>
              l.localId === lLocalId ? { ...l, [field]: value } : l) }
          : s
      )
    );

  // ── S3 Upload ─────────────────────────────────────────────────────────────
  const uploadToS3 = async (sLocalId, lLocalId, file) => {
    updateLecture(sLocalId, lLocalId, 'uploadStatus', 'uploading');
    updateLecture(sLocalId, lLocalId, 'uploadProgress', 0);
    try {
      const { data } = await api.post('/courses/lectures/presigned-upload/', {
        file_name: file.name,
        file_type: file.type,
      });
      await axios.put(data.upload_url, file, {
        headers: { 'Content-Type': file.type },
        onUploadProgress: (e) =>
          updateLecture(sLocalId, lLocalId, 'uploadProgress',
            Math.round((e.loaded / e.total) * 100)),
      });
      updateLecture(sLocalId, lLocalId, 's3_key', data.s3_key);
      updateLecture(sLocalId, lLocalId, 'uploadStatus', 'done');
    } catch {
      updateLecture(sLocalId, lLocalId, 'uploadStatus', 'error');
    }
  };

  // ── Save all sections + lectures ──────────────────────────────────────────
  const handleSave = async () => {
    setErrorMsg('');
    setSavedMsg('');

    // Validate
    for (const sec of sections) {
      if (!sec.title.trim()) { setErrorMsg('كل قسم لازم يكون ليه عنوان'); return; }
      for (const lec of sec.lectures) {
        if (!lec.title.trim()) { setErrorMsg('كل ليكتشر لازم يكون ليه عنوان'); return; }
        if (lec.video_type === 'upload' && !lec.s3_key) {
          setErrorMsg(`ليكتشر "${lec.title}" لسه ما اترفعش على S3`);
          return;
        }
        if (lec.video_type !== 'upload' && !lec.video_url) {
          setErrorMsg(`ليكتشر "${lec.title}" محتاج رابط فيديو`);
          return;
        }
      }
    }

    setSaving(true);
    try {
      for (let si = 0; si < sections.length; si++) {
        const sec = sections[si];
        const secRes = await api.post('/courses/sections/', {
          course: courseId,
          title: sec.title,
          description: sec.description,
          order: si,
        });
        const sectionId = secRes.data.id;

        for (let li = 0; li < sec.lectures.length; li++) {
          const lec = sec.lectures[li];
          await api.post('/courses/lectures/', {
            section: sectionId,
            title: lec.title,
            description: lec.description,
            video_type: lec.video_type,
            video_url: lec.video_type !== 'upload' ? lec.video_url : '',
            s3_key: lec.video_type === 'upload' ? lec.s3_key : '',
            duration_minutes: lec.duration_minutes,
            order: li,
            is_free_preview: lec.is_free_preview,
          });
        }
      }
      setSavedMsg('✅ تم الحفظ بنجاح!');
      setSections([]);   // clear draft after save
    } catch (err) {
      setErrorMsg('حدث خطأ أثناء الحفظ: ' + (err.response?.data?.detail || err.message));
    } finally {
      setSaving(false);
    }
  };

  // ── Render ────────────────────────────────────────────────────────────────
  if (loading) return <div style={s.center}>⏳ جاري التحميل...</div>;
  if (!course)  return <div style={s.center}>❌ {errorMsg || 'الكورس غير موجود'}</div>;

  const isOwner = course.instructor === JSON.parse(localStorage.getItem('user'))?.id;
  const isAdmin = JSON.parse(localStorage.getItem('user'))?.is_staff;
  if (!isOwner && !isAdmin) {
    return <div style={s.center}>🚫 ليس لديك صلاحية لإدارة هذا الكورس</div>;
  }

  return (
    <div style={s.page}>
      <div style={s.container}>

        {/* ── Header ── */}
        <div style={s.header}>
          <div>
            <button style={s.btnBack} onClick={() => navigate(-1)}>← رجوع</button>
            <h2 style={{ margin: '8px 0 4px' }}>إدارة محتوى الكورس</h2>
            <p style={s.courseName}>📚 {course.title}</p>
            <div style={{ display: 'flex', gap: 12, marginTop: 4 }}>
              <span style={s.chip(course.is_approved)}>
                {course.is_approved ? '✓ معتمد' : '⏳ في انتظار الموافقة'}
              </span>
              <span style={s.chip(course.is_published)}>
                {course.is_published ? '🌐 منشور' : '🔒 غير منشور'}
              </span>
            </div>
          </div>
          <button style={s.btnSave} onClick={handleSave} disabled={saving || sections.length === 0}>
            {saving ? '⏳ جاري الحفظ...' : '💾 حفظ الأقسام'}
          </button>
        </div>

        {/* ── Messages ── */}
        {savedMsg && <div style={s.alertSuccess}>{savedMsg}</div>}
        {errorMsg && <div style={s.alertError}>{errorMsg}</div>}

        {/* ── Existing sections (read-only summary) ── */}
        {course.sections && course.sections.length > 0 && (
          <div style={s.existingBox}>
            <h3 style={{ marginTop: 0 }}>📋 الأقسام الموجودة حالياً</h3>
            {course.sections.map((sec, si) => (
              <div key={sec.id} style={s.existingSec}>
                <strong>القسم {si + 1}: {sec.title}</strong>
                <span style={s.secMeta}>{sec.lectures?.length || 0} ليكتشر</span>
                {sec.lectures?.map((lec) => (
                  <div key={lec.id} style={s.existingLec}>
                    <span>
                      {lec.video_type === 'youtube' ? '▶' :
                       lec.video_type === 'vimeo'   ? '▶' : '🎬'}
                      {' '}{lec.title}
                    </span>
                    <span style={s.statusDot(lec.video_status)}>
                      {lec.video_status === 'approved' ? '✓ معتمد'
                       : lec.video_status === 'rejected' ? '✗ مرفوض'
                       : '⏳ معلق'}
                    </span>
                  </div>
                ))}
              </div>
            ))}
          </div>
        )}

        {/* ── New sections draft ── */}
        <div style={s.newBox}>
          <div style={s.rowBetween}>
            <h3 style={{ margin: 0 }}>➕ إضافة أقسام جديدة</h3>
            <button style={s.btnAddSec} onClick={addSection}>+ قسم جديد</button>
          </div>

          {sections.length === 0 && (
            <div style={s.emptyHint}>
              <p>اضغط "+ قسم جديد" لإضافة قسم وليكتشرات</p>
            </div>
          )}

          {sections.map((sec, si) => (
            <SectionCard key={sec.localId} sec={sec} idx={si}
              onUpdateSec={updateSection}
              onRemoveSec={removeSection}
              onAddLec={addLecture}
              onUpdateLec={updateLecture}
              onRemoveLec={removeLecture}
              onUpload={uploadToS3}
            />
          ))}

          {sections.length > 0 && (
            <button style={s.btnSaveBottom} onClick={handleSave}
              disabled={saving}>
              {saving ? '⏳ جاري الحفظ...' : '💾 حفظ الأقسام الجديدة'}
            </button>
          )}
        </div>

      </div>
    </div>
  );
};

// ─── Styles ───────────────────────────────────────────────────────────────────
const s = {
  page:       { background: '#f4f6f8', minHeight: '100vh', padding: '30px 20px' },
  container:  { maxWidth: 800, margin: '0 auto' },
  center:     { textAlign: 'center', padding: 60, fontSize: 18, color: '#666' },
  header:     { display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start',
                background: '#fff', borderRadius: 12, padding: 20, marginBottom: 20,
                boxShadow: '0 2px 12px rgba(0,0,0,0.07)' },
  courseName: { color: '#555', margin: '0 0 8px', fontSize: 15 },
  btnBack:    { background: 'none', border: 'none', color: '#007bff', cursor: 'pointer',
                fontSize: 14, padding: 0, marginBottom: 6 },
  btnSave:    { background: '#28a745', color: '#fff', border: 'none', borderRadius: 8,
                padding: '10px 22px', cursor: 'pointer', fontSize: 15, fontWeight: 600,
                opacity: 1, whiteSpace: 'nowrap' },
  btnSaveBottom: { background: '#28a745', color: '#fff', border: 'none', borderRadius: 8,
                   padding: '12px 28px', cursor: 'pointer', fontSize: 15, fontWeight: 600,
                   marginTop: 16, width: '100%' },
  chip: (active) => ({
    display: 'inline-block', fontSize: 12, padding: '3px 10px', borderRadius: 20,
    background: active ? '#d4edda' : '#fff3cd',
    color:      active ? '#155724' : '#856404',
    fontWeight: 600,
  }),
  alertSuccess: { background: '#d4edda', color: '#155724', borderRadius: 8,
                  padding: '12px 16px', marginBottom: 16, fontWeight: 500 },
  alertError:   { background: '#f8d7da', color: '#721c24', borderRadius: 8,
                  padding: '12px 16px', marginBottom: 16, fontWeight: 500 },
  existingBox: { background: '#fff', borderRadius: 12, padding: 20, marginBottom: 20,
                 boxShadow: '0 2px 12px rgba(0,0,0,0.07)' },
  existingSec: { border: '1px solid #e0e0e0', borderRadius: 8, padding: 12,
                 marginBottom: 10, display: 'flex', flexDirection: 'column', gap: 6 },
  secMeta:     { fontSize: 12, color: '#999', marginLeft: 8 },
  existingLec: { display: 'flex', justifyContent: 'space-between', alignItems: 'center',
                 padding: '6px 10px', background: '#f8f9fa', borderRadius: 6, fontSize: 14 },
  statusDot: (st) => ({
    fontSize: 11, padding: '2px 8px', borderRadius: 10, fontWeight: 600,
    background: st === 'approved' ? '#d4edda' : st === 'rejected' ? '#f8d7da' : '#fff3cd',
    color:      st === 'approved' ? '#155724' : st === 'rejected' ? '#721c24' : '#856404',
  }),
  newBox:     { background: '#fff', borderRadius: 12, padding: 20,
                boxShadow: '0 2px 12px rgba(0,0,0,0.07)' },
  emptyHint:  { textAlign: 'center', padding: '30px 0', color: '#aaa' },
  btnAddSec:  { background: '#007bff', color: '#fff', border: 'none', borderRadius: 6,
                padding: '8px 18px', cursor: 'pointer', fontWeight: 600 },
  sectionCard:{ border: '1px solid #d0e4ff', borderRadius: 10, padding: 16,
                marginTop: 16, background: '#f8fbff' },
  lectureBox: { background: '#fff', border: '1px solid #e0e0e0', borderRadius: 8,
                padding: 12, marginTop: 10 },
  rowBetween: { display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: 10 },
  label:      { display: 'block', fontSize: 13, fontWeight: 500, marginBottom: 4, marginTop: 10, color: '#444' },
  input:      { width: '100%', padding: '8px 10px', borderRadius: 6, border: '1px solid #ccc',
                fontSize: 14, boxSizing: 'border-box' },
  btnDanger:  { background: '#dc3545', color: '#fff', border: 'none', borderRadius: 6,
                padding: '5px 12px', cursor: 'pointer', fontSize: 12 },
  btnAddLec:  { background: '#6c757d', color: '#fff', border: 'none', borderRadius: 6,
                padding: '7px 14px', cursor: 'pointer', fontSize: 13, marginTop: 10 },
  uploadBox:  { background: '#f0f7ff', border: '1px dashed #90c2ff', borderRadius: 8,
                padding: 12, marginTop: 8 },
  fileInfo:   { display: 'flex', justifyContent: 'space-between', background: '#fff',
                borderRadius: 6, padding: '6px 10px', marginTop: 6, border: '1px solid #ddd', fontSize: 13 },
  btnUpload:  { background: '#0066cc', color: '#fff', border: 'none', borderRadius: 6,
                padding: '9px 16px', cursor: 'pointer', fontSize: 13, marginTop: 8, width: '100%', fontWeight: 600 },
  btnSmGray:  { background: '#6c757d', color: '#fff', border: 'none', borderRadius: 6,
                padding: '4px 10px', cursor: 'pointer', fontSize: 12, marginLeft: 8 },
  uploadDone: { display: 'flex', alignItems: 'center', justifyContent: 'space-between',
                background: '#d4edda', borderRadius: 6, padding: '8px 12px', marginTop: 8,
                color: '#155724', fontWeight: 500, fontSize: 13 },
  progressWrap: { background: '#e9ecef', borderRadius: 6, height: 18, overflow: 'hidden' },
  progressBar:  { background: '#007bff', height: '100%', transition: 'width 0.3s' },
  successTxt:   { color: '#28a745', fontSize: 13, marginTop: 6 },
};

export default ManageCourse;
